/**
 * @name SCPWikiDownDetector
 * @version 1.0.0
 * @author Danjon56
 * @authorId 1330673713359618079
 * @source https://github.com/sixeightyfour/betterdiscord-wikidot-down-bot/blob/main/SCPWikiDownDetector.plugin.js
 * @description Adds a toolbar button to manually check scp-wiki.wikidot.com status and view local status history.
 */

module.exports = class SCPWikiDownDetector {
    constructor() {
        this.pluginName = "SCPWikiDownDetector";

        this.defaultSettings = {
            checkUrl: "https://scp-wiki.wikidot.com/",
            autoCheckEnabled: true,
            checkIntervalSeconds: 60,
            failThreshold: 10,
            slowResponseThresholdSeconds: 30,
            httpTimeoutSeconds: 45,
            historyLimit: 25,

            // "I Fucked Up..."
            notificationImageUrl: "data:image/png;base64,",
            notificationPosition: "top-right"
        };

        this.settings = {};
        this.autoCheckTimer = null;
        this.headerObserver = null;

        // Discord's :bangbang: Emoji
        this.embeddedBangbangMask = "data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 36 36'%3E%3Cpath fill='%23000' d='M7 4a3 3 0 0 1 3-3h2a3 3 0 0 1 3 3v18a3 3 0 0 1-3 3h-2a3 3 0 0 1-3-3V4zm14 0a3 3 0 0 1 3-3h2a3 3 0 0 1 3 3v18a3 3 0 0 1-3 3h-2a3 3 0 0 1-3-3V4zM7 30a4 4 0 1 1 8 0a4 4 0 0 1-8 0zm14 0a4 4 0 1 1 8 0a4 4 0 0 1-8 0z'/%3E%3C/svg%3E";
        this.buttonId = "scp-wiki-detector-toolbar-button";
        this.modalId = "scp-wiki-detector-modal";
        this.styleId = "scp-wiki-detector-style";

        this.consecutiveFailures = 0;

        this.status = {
            state: "UNKNOWN",
            detail: "No checks have been run yet.",
            responseTimeSeconds: null,
            lastCheckedAt: null
        };

        this.history = [];
    }

    getName() {
        return this.pluginName;
    }

    getAuthor() {
        return "Danjon56";
    }

    getDescription() {
        return "Adds a toolbar button to manually check scp-wiki.wikidot.com status and view local status history.";
    }

    getVersion() {
        return "1.0.0";
    }

    load() {
        const savedSettings = BdApi.Data.load(this.pluginName, "settings") || {};
        this.settings = Object.assign({}, this.defaultSettings, savedSettings);

        const savedHistory = BdApi.Data.load(this.pluginName, "history") || [];
        this.history = Array.isArray(savedHistory) ? savedHistory : [];

        const savedStatus = BdApi.Data.load(this.pluginName, "status");
        if (savedStatus && typeof savedStatus === "object") {
            this.status = Object.assign({}, this.status, savedStatus);
        }

        const savedFailureStreak = BdApi.Data.load(this.pluginName, "consecutiveFailures");
        this.consecutiveFailures = Number.isFinite(savedFailureStreak)
            ? savedFailureStreak
            : 0;
    }

    start() {
        this.injectStyles();
        this.installHeaderObserver();
        this.injectToolbarButton();

        if (this.settings.autoCheckEnabled) {
            this.startAutoChecks();
        }
    }

    stop() {
        this.stopAutoChecks();
        this.removeToolbarButton();
        this.removeModal();
        this.removeNotifications();
        this.removeStyles();

        if (this.headerObserver) {
            this.headerObserver.disconnect();
            this.headerObserver = null;
        }
    }

    saveSettings() {
        BdApi.Data.save(this.pluginName, "settings", this.settings);
    }

    saveState() {
        BdApi.Data.save(this.pluginName, "history", this.history);
        BdApi.Data.save(this.pluginName, "status", this.status);
        BdApi.Data.save(this.pluginName, "consecutiveFailures", this.consecutiveFailures);
    }

    // Automatic Requests for Monitoring Site Status
    startAutoChecks() {
        this.stopAutoChecks();

        this.runCheck(false);

        this.autoCheckTimer = setInterval(() => {
            this.runCheck(false);
        }, this.settings.checkIntervalSeconds * 1000);
    }

    stopAutoChecks() {
        if (this.autoCheckTimer) {
            clearInterval(this.autoCheckTimer);
            this.autoCheckTimer = null;
        }
    }

    installHeaderObserver() {
        this.headerObserver = new MutationObserver(() => {
            this.injectToolbarButton();
        });

        this.headerObserver.observe(document.body, {
            childList: true,
            subtree: true
        });
    }

    // Selects Toolbar
    findToolbar() {
        const selectors = [
            '[class*="toolbar"]',
            '[aria-label="Channel header"] [class*="toolbar"]',
            'section[aria-label="Channel header"] [class*="toolbar"]'
        ];

        for (const selector of selectors) {
            const matches = Array.from(document.querySelectorAll(selector));

            const likelyToolbar = matches.find(element => {
                const rect = element.getBoundingClientRect();
                return rect.width > 80 && rect.height > 20;
            });

            if (likelyToolbar) {
                return likelyToolbar;
            }
        }

        return null;
    }

    // Adds Button to Discord Toolbar
    injectToolbarButton() {
        if (document.getElementById(this.buttonId)) {
            return;
        }

        const toolbar = this.findToolbar();

        if (!toolbar) {
            return;
        }

        const button = document.createElement("button");
        button.id = this.buttonId;
        button.className = "scp-wiki-detector-button";
        button.type = "button";
        button.title = "WikiDown Detector";
        button.setAttribute("aria-label", "WikiDown Detector");
        button.innerHTML = `<span class="scp-wiki-detector-bangbang-icon"></span>`;
        button.style.setProperty("--scp-wiki-bangbang-mask", `url("${this.embeddedBangbangMask}")`);

        button.addEventListener("click", () => {
            this.openModal();
        });

        toolbar.prepend(button);
        this.updateToolbarButton();
    }

    removeToolbarButton() {
        const button = document.getElementById(this.buttonId);
        if (button) {
            button.remove();
        }
    }

    // Changes Icon to Match Current Status (green, yellow, red)
    updateToolbarButton() {
        const button = document.getElementById(this.buttonId);

        if (!button) {
            return;
        }

        button.classList.remove(
            "scp-wiki-detector-unknown",
            "scp-wiki-detector-up",
            "scp-wiki-detector-slow",
            "scp-wiki-detector-down"
        );

        if (this.status.state === "UP") {
            button.classList.add("scp-wiki-detector-up");
        } else if (this.status.state === "SLOW") {
            button.classList.add("scp-wiki-detector-slow");
        } else if (this.status.state === "DOWN") {
            button.classList.add("scp-wiki-detector-down");
        } else {
            button.classList.add("scp-wiki-detector-unknown");
        }

        button.title = `Wikidot status: ${this.status.state}\n${this.status.detail}`;
    }

    // HTTP Request
    async checkSite() {
        const startedAt = performance.now();
        const timeoutMs = this.settings.httpTimeoutSeconds * 1000;

        let timeoutId = null;

        try {
            const timeoutPromise = new Promise((_, reject) => {
                timeoutId = setTimeout(() => {
                    reject(new Error(`Request timed out after ${this.settings.httpTimeoutSeconds}s`));
                }, timeoutMs);
            });

            const requestPromise = BdApi.Net.fetch(this.settings.checkUrl, {
                method: "GET",
                headers: {
                    "User-Agent": "SCPWikiDownDetector/2.0 BetterDiscord",
                    "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
                    "Cache-Control": "no-cache"
                }
            });

            const response = await Promise.race([
                requestPromise,
                timeoutPromise
            ]);

            const elapsedSeconds = (performance.now() - startedAt) / 1000;
            const statusCode = response.status || 0;

            const healthy = statusCode >= 200 && statusCode < 400;
            const slow = elapsedSeconds >= this.settings.slowResponseThresholdSeconds;

            return {
                healthy,
                slow,
                elapsedSeconds,
                detail: `HTTP ${statusCode} in ${elapsedSeconds.toFixed(2)}s`
            };
        } catch (error) {
            const elapsedSeconds = (performance.now() - startedAt) / 1000;
            const message = error && error.message ? error.message : String(error);

            return {
                healthy: false,
                slow: false,
                elapsedSeconds,
                detail: `Request error: ${message}`
            };
        } finally {
            if (timeoutId) {
                clearTimeout(timeoutId);
            }
        }
    }

    // Determines and Stores Status from Last Request
    async runCheck(showToast) {
        const previousState = this.status.state;
        const wasDown = previousState === "DOWN";

        const result = await this.checkSite();

        if (result.healthy) {
            this.consecutiveFailures = 0;

            if (result.slow) {
                this.status.state = "SLOW";
            } else {
                this.status.state = "UP";
            }
        } else {
            this.consecutiveFailures += 1;

            if (this.consecutiveFailures >= this.settings.failThreshold) {
                this.status.state = "DOWN";
            } else {
                this.status.state = "SLOW";
            }
        }

        this.status.detail = result.detail;
        this.status.responseTimeSeconds = result.elapsedSeconds;
        this.status.lastCheckedAt = new Date().toISOString();

        this.addHistoryEntry({
            timestamp: this.status.lastCheckedAt,
            state: this.status.state,
            detail: this.status.detail,
            responseTimeSeconds: this.status.responseTimeSeconds,
            failureStreak: this.consecutiveFailures
        });

        this.saveState();
        this.updateToolbarButton();
        this.refreshModal();

        const isDown = this.status.state === "DOWN";
        const recovered = wasDown && !isDown;
        const newlyDown = !wasDown && isDown;

        if (newlyDown) {
            this.showOutagePopup();
        }

        if (recovered) {
            this.showRecoveryPopup();
        }

        if (showToast) {
            BdApi.UI.showToast(`SCP Wiki: ${this.status.state} — ${this.status.detail}`, {
                type: this.getToastType(),
                timeout: 5000
            });
        }

        return result;
    }

    getNotificationHost() {
        let host = document.getElementById("scp-wiki-detector-notification-host");

        if (host) {
            return host;
        }

        host = document.createElement("div");
        host.id = "scp-wiki-detector-notification-host";
        host.className = `scp-wiki-detector-notification-host ${this.getNotificationPositionClass()}`;

        document.body.appendChild(host);

        return host;
    }

    getNotificationPositionClass() {
        switch (this.settings.notificationPosition) {
            case "top-left":
                return "scp-wiki-detector-notification-top-left";
            case "bottom-left":
                return "scp-wiki-detector-notification-bottom-left";
            case "bottom-right":
                return "scp-wiki-detector-notification-bottom-right";
            case "top-right":
            default:
                return "scp-wiki-detector-notification-top-right";
        }
    }

    // Adds Notification
    showPersistentNotification(options) {
        const host = this.getNotificationHost();

        const existing = document.getElementById(options.id);
        if (existing) {
            existing.remove();
        }

        const notification = document.createElement("div");
        notification.id = options.id;
        notification.className = `scp-wiki-detector-notification scp-wiki-detector-notification-${options.type}`;

        const imageHtml = this.settings.notificationImageUrl
            ? `<img class="scp-wiki-detector-notification-image" src="${this.escapeAttribute(this.settings.notificationImageUrl)}" alt="">`
            : "";

        notification.innerHTML = `
            ${imageHtml}

            <div class="scp-wiki-detector-notification-body">
                <div class="scp-wiki-detector-notification-header">
                    <div class="scp-wiki-detector-notification-title">
                        ${this.escapeHtml(options.title)}
                    </div>

                    <button class="scp-wiki-detector-notification-close" type="button" aria-label="Close notification">
                        ×
                    </button>
                </div>

                <div class="scp-wiki-detector-notification-message">
                    ${this.escapeHtml(options.message)}
                </div>
            </div>
        `;

        notification
            .querySelector(".scp-wiki-detector-notification-close")
            .addEventListener("click", () => {
                notification.remove();
            });

        host.prepend(notification);
    }

    // Removes Notification
    removeNotifications() {
        const host = document.getElementById("scp-wiki-detector-notification-host");
        if (host) {
            host.remove();
        }
    }

    // Notification: Site has Failed Required Consecutive Checks
    showOutagePopup() {
        this.showPersistentNotification({
            id: "scp-wiki-outage",
            type: "down",
            title: "IT'S SO OVER",
            message: [
                `The site has failed ${this.consecutiveFailures} checks in a row.`,
                "",
                `Latest result: ${this.status.detail}`,
                `Checked URL: ${this.settings.checkUrl}`,
                `Time: ${this.formatDate(this.status.lastCheckedAt)}`
            ].join("\n")
        });

        BdApi.UI.showToast("IT'S SO OVER", {
            type: "error",
            timeout: 10000
        });
    }

    // Notification: Site has Good Connection Again
    showRecoveryPopup() {
        this.showPersistentNotification({
            id: "scp-wiki-recovery",
            type: "up",
            title: "WE ARE SO BACK",
            message: [
                "The site appears to be reachable again.",
                "",
                `Latest result: ${this.status.detail}`,
                `Checked URL: ${this.settings.checkUrl}`,
                `Time: ${this.formatDate(this.status.lastCheckedAt)}`
            ].join("\n")
        });

        BdApi.UI.showToast("WE ARE SO BACK", {
            type: "success",
            timeout: 10000
        });
    }

    // Creates History Log in Menu
    addHistoryEntry(entry) {
        this.history.unshift(entry);

        if (this.history.length > this.settings.historyLimit) {
            this.history = this.history.slice(0, this.settings.historyLimit);
        }
    }

    // Notification Helper
    getToastType() {
        if (this.status.state === "UP") {
            return "success";
        }

        if (this.status.state === "SLOW") {
            return "warning";
        }

        if (this.status.state === "DOWN") {
            return "error";
        }

        return "info";
    }

    // Menu
    openModal() {
        this.removeModal();

        const backdrop = document.createElement("div");
        backdrop.id = this.modalId;
        backdrop.className = "scp-wiki-detector-backdrop";

        backdrop.innerHTML = `
            <div class="scp-wiki-detector-modal">
                <div class="scp-wiki-detector-modal-header">
                    <div>
                        <h2>WikiDown Detector</h2>
                        <div class="scp-wiki-detector-subtitle">Feel like Wikidot's slow? Check here!</div>
                    </div>
                    <button class="scp-wiki-detector-close" type="button" aria-label="Close">×</button>
                </div>

                <div class="scp-wiki-detector-status-card">
                    <div class="scp-wiki-detector-state-row">
                        <span class="scp-wiki-detector-pill ${this.getStateClass()}">${this.escapeHtml(this.status.state)}</span>
                        <span class="scp-wiki-detector-last-check">${this.escapeHtml(this.formatLastChecked())}</span>
                    </div>
                    <div class="scp-wiki-detector-detail">${this.escapeHtml(this.status.detail)}</div>
                    <div class="scp-wiki-detector-meta">
                        Failure streak: ${this.consecutiveFailures}/${this.settings.failThreshold}
                    </div>
                </div>

                <div class="scp-wiki-detector-actions">
                    <button class="scp-wiki-detector-primary" type="button" data-action="check">Run check now</button>
                    <button class="scp-wiki-detector-secondary" type="button" data-action="clear-history">Clear history</button>
                    <button class="scp-wiki-detector-secondary" type="button" data-action="toggle-auto">
                        ${this.settings.autoCheckEnabled ? "Disable auto-checks" : "Enable auto-checks"}
                    </button>
                </div>

                <h3>Status history</h3>
                <div class="scp-wiki-detector-history">
                    ${this.renderHistory()}
                </div>

                <h3>Settings</h3>
                <div class="scp-wiki-detector-settings">
                    ${this.renderSettings()}
                </div>
            </div>
        `;

        document.body.appendChild(backdrop);

        backdrop.addEventListener("click", event => {
            if (event.target === backdrop) {
                this.removeModal();
            }
        });

        backdrop.querySelector(".scp-wiki-detector-close").addEventListener("click", () => {
            this.removeModal();
        });

        backdrop.querySelector('[data-action="check"]').addEventListener("click", async event => {
            const button = event.currentTarget;
            button.disabled = true;
            button.textContent = "Checking...";

            await this.runCheck(true);

            button.disabled = false;
            button.textContent = "Run check now";
        });

        backdrop.querySelector('[data-action="clear-history"]').addEventListener("click", () => {
            this.history = [];
            this.saveState();
            this.refreshModal();
        });

        backdrop.querySelector('[data-action="toggle-auto"]').addEventListener("click", () => {
            this.settings.autoCheckEnabled = !this.settings.autoCheckEnabled;
            this.saveSettings();

            if (this.settings.autoCheckEnabled) {
                this.startAutoChecks();
            } else {
                this.stopAutoChecks();
            }

            this.refreshModal();
        });

        this.attachSettingsHandlers(backdrop);
    }

    refreshModal() {
        const modal = document.getElementById(this.modalId);

        if (!modal) {
            return;
        }

        this.openModal();
    }

    removeModal() {
        const modal = document.getElementById(this.modalId);
        if (modal) {
            modal.remove();
        }
    }

    renderHistory() {
        if (!this.history.length) {
            return `<div class="scp-wiki-detector-empty">No status history yet.</div>`;
        }

        return this.history.map(entry => {
            return `
                <div class="scp-wiki-detector-history-row">
                    <span class="scp-wiki-detector-pill ${this.getStateClass(entry.state)}">${this.escapeHtml(entry.state)}</span>
                    <div class="scp-wiki-detector-history-main">
                        <div>${this.escapeHtml(entry.detail)}</div>
                        <div class="scp-wiki-detector-history-time">
                            ${this.escapeHtml(this.formatDate(entry.timestamp))}
                            · Failure streak: ${Number(entry.failureStreak || 0)}
                        </div>
                    </div>
                </div>
            `;
        }).join("");
    }

    renderSettings() {
        return `
            <label>
                Check URL
                <input type="text" data-setting="checkUrl" value="${this.escapeAttribute(this.settings.checkUrl)}">
            </label>

            <label>
                Check interval, seconds
                <input type="number" min="10" max="86400" data-setting="checkIntervalSeconds" value="${Number(this.settings.checkIntervalSeconds)}">
            </label>

            <label>
                Failure threshold
                <input type="number" min="1" max="100" data-setting="failThreshold" value="${Number(this.settings.failThreshold)}">
            </label>

            <label>
                Slow response threshold, seconds
                <input type="number" min="1" max="300" data-setting="slowResponseThresholdSeconds" value="${Number(this.settings.slowResponseThresholdSeconds)}">
            </label>

            <label>
                HTTP timeout, seconds
                <input type="number" min="1" max="300" data-setting="httpTimeoutSeconds" value="${Number(this.settings.httpTimeoutSeconds)}">
            </label>
        `;
    }

    attachSettingsHandlers(root) {
        const inputs = Array.from(root.querySelectorAll("[data-setting]"));

        for (const input of inputs) {
            input.addEventListener("change", () => {
                const key = input.getAttribute("data-setting");

                if (!key) {
                    return;
                }

                if (input.type === "number") {
                    const value = Number(input.value);

                    if (!Number.isFinite(value)) {
                        return;
                    }

                    this.settings[key] = value;
                } else {
                    this.settings[key] = input.value.trim();
                }

                this.saveSettings();

                if (
                    key === "checkIntervalSeconds" ||
                    key === "httpTimeoutSeconds"
                ) {
                    if (this.settings.autoCheckEnabled) {
                        this.startAutoChecks();
                    }
                }

                this.updateToolbarButton();
            });
        }
    }

    // Formatting Pill Icon
    getStateClass(state) {
        const resolvedState = state || this.status.state;

        if (resolvedState === "UP") {
            return "scp-wiki-detector-pill-up";
        }

        if (resolvedState === "SLOW") {
            return "scp-wiki-detector-pill-slow";
        }

        if (resolvedState === "DOWN") {
            return "scp-wiki-detector-pill-down";
        }

        return "scp-wiki-detector-pill-unknown";
    }

    formatLastChecked() {
        if (!this.status.lastCheckedAt) {
            return "Never checked";
        }

        return `Last checked: ${this.formatDate(this.status.lastCheckedAt)}`;
    }

    formatDate(value) {
        try {
            return new Date(value).toLocaleString();
        } catch {
            return "Unknown time";
        }
    }

    escapeHtml(value) {
        return String(value)
            .replaceAll("&", "&amp;")
            .replaceAll("<", "&lt;")
            .replaceAll(">", "&gt;")
            .replaceAll('"', "&quot;")
            .replaceAll("'", "&#039;");
    }

    escapeAttribute(value) {
        return this.escapeHtml(value).replaceAll("`", "&#096;");
    }

    // CSS
    injectStyles() {
        if (document.getElementById(this.styleId)) {
            return;
        }

        const style = document.createElement("style");
        style.id = this.styleId;
        style.textContent = `
            .scp-wiki-detector-button {
                width: 32px;
                height: 32px;
                border: 0;
                padding: 0;
                margin: 0 4px;
                border-radius: 4px;
                background: transparent;
                color: var(--interactive-normal);
                display: inline-flex;
                align-items: center;
                justify-content: center;
                cursor: pointer;
                position: relative;
            }

            .scp-wiki-detector-button:hover {
                color: var(--interactive-hover);
                background: var(--background-modifier-hover);
            }

            .scp-wiki-detector-up {
                color: var(--status-positive, #23a55a);
            }

            .scp-wiki-detector-slow {
                color: var(--status-warning, #f0b232);
            }

            .scp-wiki-detector-down {
                color: var(--status-danger, #f23f42);
            }

            .scp-wiki-detector-unknown {
                color: var(--interactive-muted);
            }

            .scp-wiki-detector-bangbang-icon {
                width: 22px;
                height: 22px;
                display: block;

                background-color: currentColor;

                -webkit-mask-image: var(--scp-wiki-bangbang-mask);
                mask-image: var(--scp-wiki-bangbang-mask);

                -webkit-mask-repeat: no-repeat;
                mask-repeat: no-repeat;

                -webkit-mask-position: center;
                mask-position: center;

                -webkit-mask-size: contain;
                mask-size: contain;
            }

            .scp-wiki-detector-backdrop {
                position: fixed;
                inset: 0;
                background: rgba(0, 0, 0, 0.65);
                z-index: 999999;
                display: flex;
                align-items: center;
                justify-content: center;
            }

            .scp-wiki-detector-modal {
                width: 620px;
                max-width: calc(100vw - 40px);
                max-height: calc(100vh - 40px);
                overflow: auto;

                background: #111318;
                color: #f2f3f5;

                border: 1px solid #2b2d31;
                border-radius: 8px;
                box-shadow: 0 12px 32px rgba(0, 0, 0, 0.65);
                padding: 20px;
            }

            .scp-wiki-detector-modal-header {
                display: flex;
                justify-content: space-between;
                align-items: flex-start;
                gap: 16px;
                margin-bottom: 16px;
            }

            .scp-wiki-detector-modal h2,
            .scp-wiki-detector-modal h3 {
                margin: 0 0 8px 0;
            }

            .scp-wiki-detector-subtitle {
                color: var(--text-muted);
                font-size: 13px;
                margin-top: 4px;
            }

            .scp-wiki-detector-close {
                border: 0;
                background: transparent;
                color: var(--interactive-normal);
                font-size: 26px;
                cursor: pointer;
                line-height: 1;
            }

            .scp-wiki-detector-state-row {
                display: flex;
                justify-content: space-between;
                align-items: center;
                gap: 12px;
                margin-bottom: 10px;
            }

            .scp-wiki-detector-detail {
                font-size: 15px;
                margin-bottom: 8px;
            }

            .scp-wiki-detector-pill {
                display: inline-flex;
                align-items: center;
                justify-content: center;
                min-width: 68px;
                border-radius: 999px;
                padding: 4px 10px;
                font-weight: 700;
                font-size: 12px;
            }

            .scp-wiki-detector-pill-up {
                background: rgba(35, 165, 90, 0.18);
                color: var(--status-positive, #23a55a);
            }

            .scp-wiki-detector-pill-slow {
                background: rgba(240, 178, 50, 0.18);
                color: var(--status-warning, #f0b232);
            }

            .scp-wiki-detector-pill-down {
                background: rgba(242, 63, 66, 0.18);
                color: var(--status-danger, #f23f42);
            }

            .scp-wiki-detector-pill-unknown {
                background: rgba(128, 132, 142, 0.18);
                color: var(--text-muted);
            }

            .scp-wiki-detector-actions {
                display: flex;
                flex-wrap: wrap;
                gap: 8px;
                margin-bottom: 20px;
            }

            .scp-wiki-detector-primary,
            .scp-wiki-detector-secondary {
                border: 0;
                border-radius: 4px;
                padding: 8px 12px;
                cursor: pointer;
                color: var(--button-secondary-text);
            }

            .scp-wiki-detector-primary {
                background: var(--button-positive-background, #248046);
                color: #fff;
            }

            .scp-wiki-detector-primary:hover {
                background: var(--button-positive-background-hover, #1a6334);
            }

            .scp-wiki-detector-secondary {
                background: var(--button-secondary-background, #4e5058);
                color: #fff;
            }

            .scp-wiki-detector-secondary:hover {
                background: var(--button-secondary-background-hover, #6d6f78);
            }

            .scp-wiki-detector-primary:disabled,
            .scp-wiki-detector-secondary:disabled {
                opacity: 0.6;
                cursor: not-allowed;
            }

            .scp-wiki-detector-history {
                display: flex;
                flex-direction: column;
                gap: 8px;
                margin-bottom: 20px;
            }

            .scp-wiki-detector-history-main {
                flex: 1;
                min-width: 0;
            }

            .scp-wiki-detector-settings {
                display: grid;
                gap: 10px;
            }

            .scp-wiki-detector-status-card {
                border: 1px solid #3f4147;
                border-radius: 8px;
                padding: 14px;
                margin-bottom: 16px;
                background: #1e2027;
            }

            .scp-wiki-detector-last-check,
            .scp-wiki-detector-meta,
            .scp-wiki-detector-history-time,
            .scp-wiki-detector-empty,
            .scp-wiki-detector-subtitle {
                color: #b5bac1;
                font-size: 13px;
            }

            .scp-wiki-detector-history-row {
                display: flex;
                gap: 10px;
                align-items: flex-start;
                border-bottom: 1px solid #3f4147;
                padding-bottom: 8px;
            }

            .scp-wiki-detector-settings label {
                display: grid;
                gap: 4px;
                color: #b5bac1;
                font-size: 13px;
            }

            .scp-wiki-detector-notification-host {
                position: fixed;
                z-index: 999999;
                display: flex;
                flex-direction: column;
                gap: 12px;
                pointer-events: none;
            }

            .scp-wiki-detector-notification-top-right {
                top: 24px;
                right: 24px;
            }

            .scp-wiki-detector-notification-top-left {
                top: 24px;
                left: 24px;
            }

            .scp-wiki-detector-notification-bottom-right {
                right: 24px;
                bottom: 24px;
            }

            .scp-wiki-detector-notification-bottom-left {
                left: 24px;
                bottom: 24px;
            }

            .scp-wiki-detector-notification {
                width: 380px;
                max-width: calc(100vw - 48px);
                display: flex;
                gap: 12px;
                padding: 14px;
                border-radius: 8px;
                background: #111318;
                color: #f2f3f5;
                border: 1px solid #2b2d31;
                box-shadow: 0 12px 32px rgba(0, 0, 0, 0.55);
                pointer-events: auto;
            }

            .scp-wiki-detector-notification-down {
                border-left: 5px solid #f23f42;
            }

            .scp-wiki-detector-notification-up {
                border-left: 5px solid #23a55a;
            }

            .scp-wiki-detector-notification-image {
                width: 80px;
                height: 80px;
                flex: 0 0 auto;
                object-fit: cover;
                border-radius: 6px;
                background: #1e2027;
                align-self: anchor-center;
            }

            .scp-wiki-detector-notification-body {
                flex: 1;
                min-width: 0;
            }

            .scp-wiki-detector-notification-header {
                display: flex;
                align-items: flex-start;
                justify-content: space-between;
                gap: 10px;
                margin-bottom: 8px;
            }

            .scp-wiki-detector-notification-title {
                font-weight: 700;
                font-size: 15px;
            }

            .scp-wiki-detector-notification-close {
                border: 0;
                background: transparent;
                color: #b5bac1;
                font-size: 22px;
                line-height: 1;
                cursor: pointer;
                padding: 0;
            }

            .scp-wiki-detector-notification-close:hover {
                color: #f2f3f5;
            }

            .scp-wiki-detector-notification-message {
                white-space: pre-line;
                color: #dcdee1;
                font-size: 13px;
                line-height: 1.4;
            }

            .scp-wiki-detector-settings input {
                background: #0f1117;
                color: #f2f3f5;
                border: 1px solid #3f4147;
                border-radius: 4px;
                padding: 8px;
            }

            .scp-wiki-detector-settings input:focus {
                outline: 2px solid #5865f2;
                outline-offset: 1px;
            }
        `;

        document.head.appendChild(style);
    }

    removeStyles() {
        const style = document.getElementById(this.styleId);
        if (style) {
            style.remove();
        }
    }

    getSettingsPanel() {
        const panel = document.createElement("div");
        panel.style.padding = "16px";

        const title = document.createElement("h2");
        title.textContent = "SCP Wiki Down Detector";
        panel.appendChild(title);

        const note = document.createElement("p");
        note.textContent = "Use the double exclamation marks in the channel header to open the status panel.";
        panel.appendChild(note);

        const openButton = document.createElement("button");
        openButton.textContent = "Open status panel";
        openButton.onclick = () => this.openModal();
        panel.appendChild(openButton);

        return panel;
    }
};
